493	class _DashedBorder extends CustomPainter {
494	  @override
495	  void paint(Canvas canvas, Size size) {
496	    final paint = Paint()
497	      ..color = Colors.white12
498	      ..strokeWidth = 1.5
499	      ..style = PaintingStyle.stroke;
500	
501	    const dash = 8.0;
502	    const gap = 6.0;
503	
504	    for (double x = 0; x < size.width; x += dash + gap) {
505	      canvas.drawLine(
506	          Offset(x, 0), Offset((x + dash).clamp(0, size.width), 0), paint);
507	      canvas.drawLine(Offset(x, size.height),
508	          Offset((x + dash).clamp(0, size.width), size.height), paint);
509	    }
510	    for (double y = 0; y < size.height; y += dash + gap) {
511	      canvas.drawLine(
512	          Offset(0, y), Offset(0, (y + dash).clamp(0, size.height)), paint);
513	      canvas.drawLine(Offset(size.width, y),
514	          Offset(size.width, (y + dash).clamp(0, size.height)), paint);
515	    }
516	  }
517	
518	  @override
519	  bool shouldRepaint(_) => false;
520	}
