import 'dart:convert';
import 'package:flutter/material.dart';
import 'package:http/http.dart' as http;
import 'package:image_picker/image_picker.dart';
import '../services/api_service.dart';

class GalleryScreen extends StatefulWidget {
  const GalleryScreen({super.key});

  @override
  State<GalleryScreen> createState() => _GalleryScreenState();
}

class _GalleryScreenState extends State<GalleryScreen> {
  static const String _baseUrl = 'http://10.0.2.2:8000';
  static const _gold = Color(0xFFFFC107);

  static const _slots = [
    {'key': 'face', 'label': 'Face Photo', 'isVideo': false},
    {'key': 'full_length', 'label': 'Full Length', 'isVideo': false},
    {'key': 'happy', 'label': 'Happy Photo', 'isVideo': false},
    {'key': 'funny', 'label': 'Funny Photo', 'isVideo': false},
    {'key': 'hobby', 'label': 'Hobby Photo', 'isVideo': false},
    {'key': 'video', 'label': '3-Second Video', 'isVideo': true},
  ];

  Map<String, String?> _mediaSlots = {};
  final Map<String, bool> _uploading = {};
  String? _token;
  int? _userId;
  bool _loading = true;

  @override
  void initState() {
    super.initState();
    _init();
  }

  Future<void> _init() async {
    _token = await ApiService.getToken();
    await _loadGallery();
  }

  Future<void> _loadGallery() async {
    try {
      final meResp = await http.get(
        Uri.parse('$_baseUrl/api/users/me'),
        headers: {'Authorization': 'Bearer $_token'},
      );
      if (meResp.statusCode == 200) {
        final data = jsonDecode(meResp.body) as Map<String, dynamic>;
        _userId = data['id'] as int?;
      }

      final resp = await http.get(
        Uri.parse('$_baseUrl/api/gallery'),
        headers: {'Authorization': 'Bearer $_token'},
      );
      if (resp.statusCode == 200) {
        final data = jsonDecode(resp.body) as Map<String, dynamic>;
        setState(() {
          _mediaSlots = data.map((k, v) => MapEntry(k, v as String?));
          _loading = false;
        });
      } else {
        setState(() => _loading = false);
      }
    } catch (_) {
      setState(() => _loading = false);
    }
  }

  Future<void> _pickAndUpload(String slot, bool isVideo) async {
    final picker = ImagePicker();
    XFile? file;

    if (isVideo) {
      file = await picker.pickVideo(source: ImageSource.gallery);
      if (file == null || !mounted) return;
      final confirmed = await _showVideoTrimDialog();
      if (!confirmed || !mounted) return;
    } else {
      file = await picker.pickImage(source: ImageSource.gallery, imageQuality: 85);
      if (file == null) return;
    }

    await _uploadFile(slot, file);
  }

  Future<bool> _showVideoTrimDialog() async {
    double start = 0.0;
    double end = 3.0;

    return await showDialog<bool>(
          context: context,
          builder: (ctx) => StatefulBuilder(
            builder: (ctx, setDlgState) => AlertDialog(
              backgroundColor: const Color(0xFF1A1A1A),
              title: const Text('Trim Video',
                  style: TextStyle(color: Colors.white, fontWeight: FontWeight.bold)),
              content: Column(
                mainAxisSize: MainAxisSize.min,
                crossAxisAlignment: CrossAxisAlignment.start,
                children: [
                  const Text('Select a 3-second window:',
                      style: TextStyle(color: Colors.white70, fontSize: 13)),
                  const SizedBox(height: 4),
                  const Text(
                    'Note: trimming coming soon (requires ffmpeg). Full video will be uploaded.',
                    style: TextStyle(color: Colors.white38, fontSize: 11),
                  ),
                  const SizedBox(height: 16),
                  RangeSlider(
                    values: RangeValues(start, end),
                    min: 0,
                    max: 30,
                    divisions: 60,
                    activeColor: _gold,
                    inactiveColor: Colors.white12,
                    labels: RangeLabels(
                      '${start.toStringAsFixed(1)}s',
                      '${end.toStringAsFixed(1)}s',
                    ),
                    onChanged: (v) {
                      setDlgState(() {
                        start = v.start;
                        end = (v.start + 3.0).clamp(0.0, 30.0);
                      });
                    },
                  ),
                  Text(
                    'Clip: ${start.toStringAsFixed(1)}s – ${end.toStringAsFixed(1)}s',
                    style: const TextStyle(color: Colors.white54, fontSize: 12),
                  ),
                ],
              ),
              actions: [
                TextButton(
                  onPressed: () => Navigator.pop(ctx, false),
                  child: const Text('Cancel', style: TextStyle(color: Colors.white54)),
                ),
                ElevatedButton(
                  onPressed: () => Navigator.pop(ctx, true),
                  style: ElevatedButton.styleFrom(
                    backgroundColor: _gold,
                    foregroundColor: Colors.black,
                    shape: const RoundedRectangleBorder(),
                  ),
                  child: const Text('Use this clip',
                      style: TextStyle(fontWeight: FontWeight.bold)),
                ),
              ],
            ),
          ),
        ) ??
        false;
  }

  Future<void> _uploadFile(String slot, XFile file) async {
    if (!mounted) return;
    setState(() => _uploading[slot] = true);
    try {
      final request = http.MultipartRequest(
        'POST',
        Uri.parse('$_baseUrl/api/gallery/$slot'),
      );
      request.headers['Authorization'] = 'Bearer $_token';
      request.files.add(await http.MultipartFile.fromPath('file', file.path));

      final streamed = await request.send();
      final resp = await http.Response.fromStream(streamed);

      if (resp.statusCode == 200) {
        await _loadGallery();
      } else if (mounted) {
        ScaffoldMessenger.of(context).showSnackBar(SnackBar(
          content: Text('Upload failed (${resp.statusCode})'),
          backgroundColor: Colors.redAccent,
        ));
      }
    } catch (e) {
      if (mounted) {
        ScaffoldMessenger.of(context).showSnackBar(SnackBar(
          content: Text('Error: $e'),
          backgroundColor: Colors.redAccent,
        ));
      }
    } finally {
      if (mounted) setState(() => _uploading[slot] = false);
    }
  }

  Future<void> _deleteMedia(String slot) async {
    final confirmed = await showDialog<bool>(
          context: context,
          builder: (ctx) => AlertDialog(
            backgroundColor: const Color(0xFF1A1A1A),
            title: const Text('Delete?', style: TextStyle(color: Colors.white)),
