                  final uploading = _uploading[key] ?? false;

                  return _SlotCard(
                    slotKey: key,
                    label: label,
                    isVideo: isVideo,
                    filled: filled,
                    uploading: uploading,
                    token: _token ?? '',
                    userId: _userId,
